declare class JiboLog {
    constructor(name:string);
    log(...any);
    debug(...any);
    info(...any);
    warn(...any);
    error(...any);
    iferr(err:any, ...any);
    enableDebug(name?:string|RegExp, level?:string);
    toFile(filename?, callback?:() => {});
    setDefaultLogDir(directory:string, callback?:() => {});
    toSyslog();
    enableUncaughtAndUnhandled();
    disableUncaughtAndUnhandled();
}


export = JiboLog;
